mapper.insert:
		/* wms-master-ctg-sql-oracle.xml - insertTWorkMstCtg */
		INSERT INTO TWORK_MST_CTG	(
			 CTKEY
			,OWKEY
			,CTGKEY
			,CTGLEVEL
			,CTGNAME
			,UPPERCTGKEY
			,URKEY
			,INSERTDATE
			,INSERTURKEY
			,UPDATEDATE
			,UPDATEURKEY
			,CLOSDATE
			,ICGRKEY
		 )
		VALUES	(
			 #{ctkey}
			,#{owkey}
			,#{ctgkey}
			,#{ctglv}
			,#{ctgnm}
			,COALESCE(#{upperctgkey}, 'DIR')
			,#{urkey}
			,#{sysdate}
			,#{surkey}
			,#{sysdate}
			,#{surkey}
            ,#{closdate}
			,#{icgrkey}
		)

mapper.delete:
/* wms-master-ctg-sql-oracle.xml - deleteTWorkMstCtg */
UPDATE  TWORK_MST_CTG
SET      DELYN 				= 'Y'
		,CLOSDATE		= #{sysdate}
WHERE OWKEY 		 = #{owkey}
AND   CTGKEY   		 = #{ctgkey}
AND   CTGLEVEL 		 = #{ctglv}
